var e=JSON.parse(`[{"id":"L2_1","type":"dialog","speaker":"SPENCER_FLOOR_NULL_NULL","text":{"KOREA":"…….","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"CORRIDOR_04","slots":{"L":null,"C":{"char_id":"SPENCER_FLOOR_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L3_1","type":"dialog","speaker":"SPENCER_FLOOR_NULL_NULL","text":{"KOREA":"뭐야, 저 녀석.","JPN":"何だ、あいつ。","ENG":"What's it doing here?","TWN":"那傢伙，怎麼也在這裡？"},"stage":{"bg":"CORRIDOR_04","slots":{"L":null,"C":{"char_id":"SPENCER_FLOOR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L4_1","type":"dialog","speaker":"SPENCER_FLOOR_NULL_NULL","text":{"KOREA":"난데없이 나타나더니 고위 침식체를 순식간에 해치웠어.","JPN":"いきなり現われて、高位侵食体を一瞬でやっつけた。","ENG":"It just appeared out of nowhere and defeated that high-tier C.O.","TWN":"突然出現，一下子就幹掉了高級侵蝕體。"},"stage":{"bg":"CORRIDOR_04","slots":{"L":null,"C":{"char_id":"SPENCER_FLOOR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L5_1","type":"dialog","speaker":"SPENCER_FLOOR_NULL_NULL","text":{"KOREA":"설마 이터니움을 노리고 녀석을 사냥한 건가?","JPN":"まさか、エタニウムを狙ってあいつを狩ったのか？","ENG":"Did it just hunt that thing for Eternium?","TWN":"難道它的目標是永恆之金嗎？"},"stage":{"bg":"CORRIDOR_04","slots":{"L":null,"C":{"char_id":"SPENCER_FLOOR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L8_1","type":"dialog","speaker":"SPIRIT_RAS_NULL_ONLY","text":{"KOREA":"러처는 지금 겁이 나는 거예요.","JPN":"ラッチャーは今怖いの。","ENG":"Lurcher is scared right now.","TWN":"獵犬現在很害怕。"},"stage":{"bg":"CORRIDOR_04","slots":{"L":{"char_id":"SPENCER_FLOOR_NULL_NULL","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"SPIRIT_RAS_NULL_ONLY","face":"UNIT_IDLE"}}}},{"id":"L9_1","type":"dialog","speaker":"SPIRIT_RAS_NULL_ONLY","text":{"KOREA":"여기서 벗어나고 싶어해요.","JPN":"ここから出たいと思ってる。","ENG":"He wants to leave this place.","TWN":"它想離開這裡。"},"stage":{"bg":"CORRIDOR_04","slots":{"L":{"char_id":"SPENCER_FLOOR_NULL_NULL","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"SPIRIT_RAS_NULL_ONLY","face":"UNIT_IDLE"}}}},{"id":"L10_1","type":"dialog","speaker":"SPENCER_FLOOR_NULL_NULL","text":{"KOREA":"뭐?","JPN":"何？","ENG":"What?","TWN":"什麼？"},"stage":{"bg":"CORRIDOR_04","slots":{"L":{"char_id":"SPENCER_FLOOR_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SPIRIT_RAS_NULL_ONLY","face":"UNIT_IDLE"}}}},{"id":"L11_1","type":"dialog","speaker":"SPENCER_FLOOR_NULL_NULL","text":{"KOREA":"저 큰 녀석이… 겁에 질려 있다고?","JPN":"あのデカいやつが……怖がってる？","ENG":"That huge thing is... scared?","TWN":"那個大傢伙……在害怕？"},"stage":{"bg":"CORRIDOR_04","slots":{"L":{"char_id":"SPENCER_FLOOR_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SPIRIT_RAS_NULL_ONLY","face":"UNIT_IDLE"}}}},{"id":"L13_1","type":"dialog","speaker":"SPENCER_FLOOR_NULL_NULL","text":{"KOREA":"이런, 우릴 봤어…!","JPN":"しまった、こっちを見た……！","ENG":"Dammit, it saw us...!","TWN":"糟了，它看到我們了……！"},"stage":{"bg":"CORRIDOR_04","slots":{"L":{"char_id":"SPENCER_FLOOR_NULL_NULL","face":"UNIT_HATE"},"C":null,"R":{"char_id":"SPIRIT_RAS_NULL_ONLY","face":"UNIT_IDLE"}}}},{"id":"L14_1","type":"dialog","speaker":"SPENCER_FLOOR_NULL_NULL","text":{"KOREA":"도망쳐! 셰퍼드!","JPN":"逃げて！　シェパード！","ENG":"RUN! Shepherd!","TWN":"快跑！牧羊犬！"},"stage":{"bg":"CORRIDOR_04","slots":{"L":{"char_id":"SPENCER_FLOOR_NULL_NULL","face":"UNIT_SERIOUS"},"C":null,"R":{"char_id":"SPIRIT_RAS_NULL_ONLY","face":"UNIT_IDLE"}}}},{"id":"L16_1","type":"dialog","speaker":"SPENCER_FLOOR_NULL_NULL","text":{"KOREA":"셰퍼드? 잠깐. 그쪽이 아니야.","JPN":"シェパード？　待って。そっちじゃない。","ENG":"Shepherd? Wait, you're going the wrong way.","TWN":"牧羊犬？等一下，不是那邊。"},"stage":{"bg":"CORRIDOR_04","slots":{"L":null,"C":{"char_id":"SPENCER_FLOOR_NULL_NULL","face":"UNIT_SURPRISE"},"R":{"char_id":"SPIRIT_RAS_NULL_ONLY","face":"UNIT_IDLE"}}}},{"id":"L18_1","type":"dialog","speaker":"SPIRIT_RAS_NULL_ONLY","text":{"KOREA":"도망치면…","JPN":"逃げちゃ……","ENG":"If Shepherd runs...","TWN":"逃跑的話……"},"stage":{"bg":"CORRIDOR_04","slots":{"L":null,"C":{"char_id":"SPENCER_FLOOR_NULL_NULL","face":"UNIT_IDLE"},"R":{"char_id":"SPIRIT_RAS_NULL_ONLY","face":"UNIT_IDLE"}}}},{"id":"L19_1","type":"dialog","speaker":"SPIRIT_RAS_NULL_ONLY","text":{"KOREA":"당신이 집에 못 돌아가요.","JPN":"あなたがおウチに帰れない。","ENG":"then you won't get back home.","TWN":"史賓瑟就回不了家了。"},"stage":{"bg":"CORRIDOR_04","slots":{"L":null,"C":{"char_id":"SPIRIT_RAS_NULL_ONLY","face":"UNIT_IDLE"},"R":null}}},{"id":"L20_1","type":"dialog","speaker":"SPIRIT_RAS_NULL_ONLY","text":{"KOREA":"셰퍼드는 알아요. 집에 못 가면 슬프다는 거.","JPN":"シェパード、知ってる。おウチに帰れないと悲しいって。","ENG":"Shepherd knows too. That it's sad to not be able to go home.","TWN":"牧羊犬知道。不能回家的話，史賓瑟會很傷心。"},"stage":{"bg":"CORRIDOR_04","slots":{"L":null,"C":{"char_id":"SPIRIT_RAS_NULL_ONLY","face":"UNIT_IDLE"},"R":null}}},{"id":"L21_1","type":"dialog","speaker":"SPENCER_FLOOR_NULL_NULL","text":{"KOREA":"그런 문제가 아니야! 저 녀석은 네가 겁을 줘도 도망치지 않는다고!","JPN":"そんな場合じゃない！　あいつはあなたが脅しても逃げない！","ENG":"That's not the problem! That thing won't run away even if you scare it!","TWN":"那不是重點！就算你嚇唬它，那傢伙也不會逃跑的！"},"stage":{"bg":"CORRIDOR_04","slots":{"L":null,"C":{"char_id":"SPENCER_FLOOR_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L23_1","type":"dialog","speaker":"SPIRIT_RAS_NULL_ONLY","text":{"KOREA":"맞아요. 러처는 마음이 온통 뾰족해서 겁을 주면 뭐든 해쳐요.","JPN":"そうだよ。ラッチャーは心がトゲトゲだらけで、怖がらせるとなんでも傷つける。","ENG":"You're right. Lurcher's heart is all pointy, so he'll harm anything when he's scared.","TWN":"沒錯。獵犬的心上全是尖刺，會傷害任何讓它害怕的東西。"},"stage":{"bg":"CORRIDOR_04","slots":{"L":null,"C":{"char_id":"SPENCER_FLOOR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L24_1","type":"dialog","speaker":"SPIRIT_RAS_NULL_ONLY","text":{"KOREA":"어른들은 러처가 돌연변이라서 그렇대요.","JPN":"大人たちは、ラッチャーが突然変異したからこうなったんだって。","ENG":"The adults said that's because Lurcher is a mutant.","TWN":"大人們說這是因為獵犬是一個突變種。"},"stage":{"bg":"CORRIDOR_04","slots":{"L":null,"C":{"char_id":"SPENCER_FLOOR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L25_1","type":"dialog","speaker":"SPIRIT_RAS_NULL_ONLY","text":{"KOREA":"처음 만난 당신도 그런 뾰족한 마음을 가지고 있었고요.","JPN":"初めて会った時、あなたもそんなトゲトゲの心を持ってた。","ENG":"When Shepherd first met you, you also had a pointy heart.","TWN":"牧羊犬第一次見到你時，史賓瑟的心也是這樣尖銳。"},"stage":{"bg":"CORRIDOR_04","slots":{"L":null,"C":{"char_id":"SPENCER_FLOOR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L26_1","type":"dialog","speaker":"SPENCER_FLOOR_NULL_NULL","text":{"KOREA":"뭐…?","JPN":"えっ……？","ENG":"What...?","TWN":"什麼……？"},"stage":{"bg":"CORRIDOR_04","slots":{"L":null,"C":{"char_id":"SPENCER_FLOOR_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L27_1","type":"dialog","speaker":"SPIRIT_RAS_NULL_ONLY","text":{"KOREA":"하지만 우리가 함께 할수록 당신의 마음은 변했어요.","JPN":"でも、シェパードと一緒にいればいるほど、あなたの心は変わったの。","ENG":"But as we spent time together, its shape changed.","TWN":"但我們在一起的時間越長，你的心就發生了改變。"},"stage":{"bg":"CORRIDOR_04","slots":{"L":null,"C":{"char_id":"SPENCER_FLOOR_NULL_NULL","face":"UNIT_SURPRISE"},"R":{"char_id":"SPIRIT_RAS_NULL_ONLY","face":"UNIT_IDLE"}}}},{"id":"L28_1","type":"dialog","speaker":"SPIRIT_RAS_NULL_ONLY","text":{"KOREA":"러처에게 당한 셰퍼드가 다시 눈을 떴을 때… 당신의 마음은 더 이상 뾰족하지 않았어요.","JPN":"ラッチャーにやられたシェパードがまた目覚めた時……あなたの心はもうトゲトゲじゃなかった。","ENG":"When Shepherd woke up after being attacked by Lurcher... your heart was no longer pointy.","TWN":"當牧羊犬被獵犬攻擊，再次睜開眼睛時……史賓瑟的心就不再是尖銳的模樣了。"},"stage":{"bg":"CORRIDOR_04","slots":{"L":null,"C":{"char_id":"SPENCER_FLOOR_NULL_NULL","face":"UNIT_SURPRISE"},"R":{"char_id":"SPIRIT_RAS_NULL_ONLY","face":"UNIT_PRIDE"}}}},{"id":"L29_1","type":"dialog","speaker":"SPIRIT_RAS_NULL_ONLY","text":{"KOREA":"날 아끼는 사람처럼... 주홍빛 동그라미 마음이었어요.","JPN":"シェパードを大切に思ってる人と同じ……オレンジ色の丸い心だったよ。","ENG":"It was just like the person dear to Shepherd... It was round and orange.","TWN":"就像在乎牧羊犬的人一樣……是一顆橘紅色的圓圈。"},"stage":{"bg":"CORRIDOR_04","slots":{"L":null,"C":{"char_id":"SPENCER_FLOOR_NULL_NULL","face":"UNIT_SURPRISE"},"R":{"char_id":"SPIRIT_RAS_NULL_ONLY","face":"UNIT_IDLE"}}}},{"id":"L31_1","type":"dialog","speaker":"SPENCER_FLOOR_NULL_NULL","text":{"KOREA":"위험해, 셰퍼드. 그렇게 다가가면…!","JPN":"危ない、シェパード。それ以上近づいたら……！","ENG":"It's too dangerous, Shepherd. If you get too close–!","TWN":"很危險，牧羊犬。你再這樣靠近的話……！"},"stage":{"bg":"CORRIDOR_04","slots":{"L":null,"C":{"char_id":"SPENCER_FLOOR_NULL_NULL","face":"UNIT_SURPRISE"},"R":{"char_id":"SPIRIT_RAS_NULL_ONLY","face":"UNIT_IDLE"}}}},{"id":"L33_1","type":"dialog","speaker":"SPIRIT_RAS_NULL_ONLY","text":{"KOREA":"…어쩌면요.","JPN":"……もしかして、ね。","ENG":"...Maybe.","TWN":"……也許。"},"stage":{"bg":"CORRIDOR_04","slots":{"L":null,"C":{"char_id":"SPENCER_FLOOR_NULL_NULL","face":"UNIT_IDLE"},"R":{"char_id":"SPIRIT_RAS_NULL_ONLY","face":"UNIT_IDLE"}}}},{"id":"L35_1","type":"dialog","speaker":"SPIRIT_RAS_NULL_ONLY","text":{"KOREA":"러처의 뾰족한 마음은…","JPN":"ラッチャーのトゲトゲの心は……","ENG":"Lurcher's pointy heart is...","TWN":"獵犬尖銳的心……"},"stage":{"bg":"CORRIDOR_04","slots":{"L":null,"C":{"char_id":"SPENCER_FLOOR_NULL_NULL","face":"UNIT_IDLE"},"R":{"char_id":"SPIRIT_RAS_NULL_ONLY","face":"UNIT_IDLE"}}}},{"id":"L36_1","type":"dialog","speaker":"SPIRIT_RAS_NULL_ONLY","text":{"KOREA":"돌연변이라서 그런 게 아닐지도 몰라요.","JPN":"突然変異じゃないかもしれない。","ENG":"not because he's a mutant.","TWN":"並不是因為他是變種。"},"stage":{"bg":"CORRIDOR_04","slots":{"L":null,"C":{"char_id":"SPENCER_FLOOR_NULL_NULL","face":"UNIT_IDLE"},"R":{"char_id":"SPIRIT_RAS_NULL_ONLY","face":"UNIT_IDLE"}}}}]`);export{e as default};